+    pub fn is_timeout(&self) -> bool {
+        match self {
+            Self::Nats(e) => e.is_timeout(),
+            Self::Api { code: 408, .. } | Self::NotAcked => true,
+            _ => false,
+        }
+    }
+
+    /// Whether the operation should be retried.
+    #[must_use]
+    pub fn is_retryable(&self) -> bool {
+        self.is_transient()
+    }
